23	    expect(quote({ items: [{ type: "rune" }] })).toEqual({ premium: 30 });
24	  });
25	
26	  // --- Quote: component block (R2) ---
27	  it("2 runes → 50 G base premium (no block)", () => {
28	    expect(quote({ items: [{ type: "rune" }, { type: "rune" }] })).toEqual({
29	      premium: 55,
30	    });
