64	  it("2 runes + 1 moonstone → 75 G base premium (different types, no block)", () => {
65	    expect(
66	      quote({
67	        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
68	      }),
69	    ).toEqual({ premium: 80 });
70	  });
71	  it("3 runes + 3 moonstones → 120 G base premium (two separate blocks of 60)", () => {
72	    expect(
73	      quote({
74	        items: [
75	          { type: "rune" },
76	          { type: "rune" },
77	          { type: "rune" },
78	          { type: "moonstone" },
79	          { type: "moonstone" },
80	          { type: "moonstone" },
81	        ],
82	      }),
83	    ).toEqual({ premium: 125 });
