85	
86	  // --- Quote: item-specific modifiers (R3) ---
87	  it("cursed sword → curse adds 50% of item base (100 → +50 base premium)", () => {
88	    expect(quote({ items: [{ type: "sword", cursed: true }] })).toEqual({
89	      premium: 155,
90	    });
91	  });
92	  it("sword with enchantment exactly 5 → high-enchantment surcharge +30% applies", () => {
93	    expect(quote({ items: [{ type: "sword", enchantment: 5 }] })).toEqual({
94	      premium: 135,
95	    });
96	  });
97	  it("sword with enchantment 4 → no high-enchantment surcharge", () => {
98	    expect(quote({ items: [{ type: "sword", enchantment: 4 }] })).toEqual({
99	      premium: 105,
100	    });
101	  });
102	  it("cursed sword with enchantment ≥5 → both curse and high-enchantment surcharges apply", () => {
103	    expect(
104	      quote({ items: [{ type: "sword", cursed: true, enchantment: 5 }] }),
105	    ).toEqual({ premium: 185 });
106	  });
107	
108	  // --- Quote: policy-wide modifiers (R3) ---
109	  it("customer with exactly 2 years → 20% loyalty discount applies to policy base", () => {
110	    expect(
111	      quote({ items: [{ type: "sword" }], yearsWithMHPCO: 2 }),
