125	  // --- Quote: modifier scope on multi-item policies (R3) ---
126	  it("cursed sword (base 100) + plain amulet (base 60) → 210 G before fee (curse on sword base only)", () => {
127	    expect(
128	      quote({ items: [{ type: "sword", cursed: true }, { type: "amulet" }] }),
129	    ).toEqual({ premium: 215 });
130	  });
131	
132	  // --- Quote: integration examples (R3) ---
133	  it("newcomer (0 years) cursed sword steel ench 3 → premium 165 G (100+50 curse+10 first +5 fee)", () => {
134	    expect(
135	      quote({
136	        items: [
137	          { type: "sword", cursed: true, material: "steel", enchantment: 3 },
138	        ],
139	        yearsWithMHPCO: 0,
140	        firstInsurance: true,
141	      }),
142	    ).toEqual({ premium: 165 });
143	  });
144	  it("3-year customer 2nd quote, cursed sword steel ench 7 → premium 160 G (100+50+30-20+10-15+5)", () => {
145	    expect(
146	      quote({
147	        items: [
148	          { type: "sword", cursed: true, material: "steel", enchantment: 7 },
149	        ],
150	        yearsWithMHPCO: 3,
151	        followUp: true,
152	        firstInsurance: true,
153	      }),
154	    ).toEqual({ premium: 160 });
155	  });
156	
157	  // --- Quote: rounding (R4) ---
158	  it.todo("premium yielding 197.5 G → final premium 198 G (rounded up)");
159	
160	  // --- Claim: standard reimbursement (R5) ---
161	  it.todo("steel sword ench 3, damage 500 → payout 400 G (full minus 100 deductible)");
162	  it.todo("rune (value 250), damage 200 → payout 100 G (no clause; minus 100 deductible)");
163	
164	  // --- Claim: deductible per damage event (R5) ---
165	  it.todo("dragon attack damages sword (500) + amulet (300) → payout 600 G (deductible per item)");
166	
167	  // --- Claim: enchantment threshold vs dragon material (R5) ---
168	  it.todo("dragon sword ench exactly 8, damage 1000 → payout 400 G (50% rule wins, then deductible)");
169	  it.todo("dragon sword ench 9, damage 1000 → payout 400 G (both clauses, 50% wins: 500−100)");
170	  it.todo("dragon sword ench 5, damage 800 → payout 700 G (dragon clause only: 800−100)");
171	  it.todo("steel sword ench 9, damage 1000 → payout 400 G (high-enchantment only: 500−100)");
172	
173	  // --- Claim: payout rounding (R4) ---
174	  it.todo("payout yielding 350.5 G → final payout 350 G (rounded down)");
175	
176	  // --- Claim: cap (R5) ---
177	  it.todo("policy sword + amulet → insurance sum 1600 G, cap 3200 G");
178	  it.todo("cursed sword (modified premium 165 G) → cap 2000 G (based on unmodified insurance value)");
179	  it.todo("policy sword + 3 runes (block) → insurance sum 1750 G (block affects premium only, not sum)");
180	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
181	  it.todo("sword (cap 2000), first claim 1500 → payout 1400 G, remainingCap 600 G");
182	  it.todo("sword (cap 2000), second successive claim 1500 → payout 600 G (capped), remainingCap 0 G");
183	
184	  // --- CLI surface (R7) ---
185	  it.todo("CLI reads JSON scenario from stdin and writes {results:[...]} to stdout");
186	  it.todo("CLI processes quote then claim sequentially; claim references policy by zero-based index");
187	
188	  // --- CLI error cases (R6) ---
189	  it.todo("CLI: quote with unknown item type (broomstick) → non-zero exit, error to stderr, no results on stdout");
190	  it.todo("CLI: claim references item not in policy (amulet, only sword insured) → non-zero exit + stderr");
191	  it.todo("CLI: claim damage amount -200 → non-zero exit + stderr");
192	  it.todo("CLI: more damage entries of a type than insured (2 sword damages, 1 sword) → non-zero exit, claim rejected");
193	});
