node -e '
// search for item combos yielding 197.5 before fee+rounding using current rules
const bases={sword:100,amulet:60,staff:80,potion:40,rune:25,moonstone:25};
function itemBase(t,cursed,ench){let b=bases[t];let s=0;if(ench>=5)s+=0.3;if(cursed)s+=0.5;return b*(1+s);}
// try up to 2 items, optional cursed/ench, plus optional firstInsurance/followUp/loyalty
const types=Object.keys(bases);
const out=[];
for(const t1 of types)for(const c1 of [false,true])for(const e1 of [0,5]){
  for(const t2 of [null,...types])for(const c2 of [false,true])for(const e2 of [0,5]){
    if(t2===null&&(c2||e2))continue;
    let base=itemBase(t1,c1,e1);
    let unmod=bases[t1];
    if(t2!==null){base+=itemBase(t2,c2,e2);unmod+=bases[t2];}
    for(const fi of [false,true])for(const fu of [false,true])for(const ly of [false,true]){
      let p=base;
      if(fi)p+=unmod*0.1;
      if(fu)p-=unmod*0.15;
      if(ly)p-=unmod*0.2;
      p+=5;
      if(Math.abs(p-197.5)<1e-9){
        out.push({t1,c1,e1,t2,c2,e2,fi,fu,ly,p});
      }
    }
  }
}
console.log(out.length, "matches");
out.slice(0,10).forEach(o=>console.log(JSON.stringify(o)));
'

