it("premium yielding 197.5 G → final premium 198 G (rounded up)", () => {
  expect(
    quote({
      items: [
        { type: "sword", cursed: true, enchantment: 5 },
        { type: "rune" },
      ],
      yearsWithMHPCO: 2,
      firstInsurance: true,
    }),
